queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?cruise_ship a :Cruise_Ships .
    ?cruise_ship p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?all_inclusive_resort a :All_Inclusive_Resort .
    ?all_inclusive_resort p:name ?name .
    ?all_inclusive_resort p:activities ?activities_f .
    FILTER(STR(?activities_f) = "Dance Class")
    BIND(?name AS ?o0)
  }
}

